              {!isMobile && <div style={{ fontFamily: "'adobe-garamond-pro', 'Garamond', 'Cormorant Garamond', Georgia, serif", fontSize: 11, letterSpacing: "0.16em", color: "#D9C7A9", fontStyle: "italic", marginTop: 3, whiteSpace: "nowrap" }}>Forging the Leaders of Tomorrow</div>}
