// INTERACTIVE DAILY SCHEDULE COMPONENT
// ─────────────────────────────────────────────
function ScheduleDetail({ block }) {
  if (!block || !block.block) return null;
  const isBreak = !block.instructor;
  return (
    <div className="mod-content" style={{ padding: "32px 36px", background: "#010000", borderTop: "1px solid rgba(0,0,0,.07)" }}>
      {isBreak ? (
        <>
          <p style={{ fontFamily: "'Cormorant Garamond', Georgia, serif", fontSize: 22, fontWeight: 600, color:"#010000", letterSpacing: "0.01em", marginBottom: 14, lineHeight: 1.1 }}>{block.block}</p>
          <p style={{ fontFamily: "'Lato', sans-serif", fontSize: 15, color:"#010000", fontWeight: 300, lineHeight: 1.85 }}>{block.desc}</p>
        </>
      ) : (
        <>
          <div style={{ display: "flex", gap: 14, alignItems: "center", marginBottom: 20 }}>
            {block.img ? (
              <div style={{ width: 48, height: 48, flexShrink: 0, overflow: "hidden", border: "1px solid rgba(0,0,0,.1)", borderRadius: "50%" }}>
                <img src={block.img} alt={block.instructor || ""} style={{ width: "100%", height: "100%", objectFit: "cover", objectPosition: "center top" }} onError={e => e.target.style.display = "none"} />
              </div>
            ) : (
              <div style={{ width: 48, height: 48, flexShrink: 0, border: "1px solid rgba(0,0,0,.1)", display: "flex", alignItems: "center", justifyContent: "center", background:"#010000" }}>
                <span style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 18, color:"#d8b78c" }}>✦</span>
              </div>
            )}
            <div>
              <p style={{ fontFamily: "'Cormorant Garamond', Georgia, serif", fontSize: 17, color:"#010000", fontWeight: 600, marginBottom: 2 }}>{block.instructor}</p>
              <p style={{ fontFamily: "'Forum', sans-serif", fontSize: 9, color:"#010000", letterSpacing: "0.18em", textTransform: "uppercase", fontWeight: 600 }}>{block.role}</p>
            </div>
          </div>
          <p style={{ fontFamily: "'Cormorant Garamond', Georgia, serif", fontSize: 22, fontWeight: 600, color:"#010000", letterSpacing: "0.01em", marginBottom: 14, lineHeight: 1.1 }}>{block.block}</p>
          <p style={{ fontFamily: "'Lato', sans-serif", fontSize: 15, color:"#010000", fontWeight: 300, lineHeight: 1.9 }}>{block.desc}</p>
        </>
      )}
    </div>
  );
}

function DailyScheduleBlock({ schedule, title, subtitle }) {
  const [active, setActive] = useState(0);
  const isMobile = useIsMobile();

  const toggle = (i) => setActive(active === i ? null : i);

  return (
    <div style={{ background: "#010000", border: "1px solid rgba(0,0,0,.08)" }}>
      {/* Title */}
      <div style={{ padding: isMobile ? "20px 20px 16px" : "28px 36px 22px", borderBottom: "1px solid rgba(0,0,0,.07)", background:"#010000" }}>
        <p style={{ fontFamily: "'Forum', sans-serif", fontSize: 9, letterSpacing: "0.4em", color:"#010000", fontWeight: 700, textTransform: "uppercase", marginBottom: 8 }}>{title}</p>
        <p style={{ fontFamily: "'Cormorant Garamond', Georgia, serif", fontSize: isMobile ? 14 : 17, color:"#010000", fontWeight: 400, letterSpacing: "0.01em" }}>{subtitle}</p>
      </div>

      {isMobile ? (
        <div>
          {(schedule || []).map((s, i) => (
            <div key={i}>
              <div onClick={() => toggle(i)} style={{ padding: "14px 20px", cursor: "pointer", borderLeft: `3px solid ${active === i ? "#d8b78c" : "transparent"}`, background: active === i ? "rgba(216,183,140,.04)" : "#FBF7EE", borderBottom: "1px solid rgba(216,183,140,.1)", display: "flex", gap: 12, alignItems: "flex-start", transition: "all .2s" }}>
                <div style={{ flexShrink: 0, minWidth: 52 }}>
                  <div style={{ fontFamily: "'Cormorant Garamond', Georgia, serif", fontSize: 18, color: active === i ? "#d8b78c" : "#010000", fontWeight: 600, lineHeight: 1 }}>{s.time}</div>
                  <div style={{ fontFamily: "'Lato', sans-serif", fontSize: 9, color:"#010000", marginTop: 2 }}>{s.dur}</div>
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontFamily: "'Cormorant Garamond', Georgia, serif", fontSize: 15, fontWeight: 600, color:"#010000", lineHeight: 1.3 }}>{s.block}</div>
                  {s.instructor && <div style={{ fontFamily: "'Lato', sans-serif", fontSize: 9, color: active === i ? "#d8b78c" : "#FBF7EE", marginTop: 2 }}>{s.instructor}</div>}
                </div>
                <span style={{ color: active === i ? "#d8b78c" : "#FBF7EE", fontSize: 16, transition: "transform .2s", transform: active === i ? "rotate(45deg)" : "none", display: "inline-block", flexShrink: 0 }}>+</span>
              </div>
              {active === i && <ScheduleDetail block={s} />}
            </div>
          ))}
        </div>
      ) : (
        <div style={{ display: "grid", gridTemplateColumns: "300px 1fr" }}>
          <div style={{ borderRight: "1px solid rgba(216,183,140,.12)", background: "#010000" }}>
            {(schedule || []).map((s, i) => (
              <div key={i} onClick={() => toggle(i)} style={{ padding: "14px 24px", cursor: "pointer", borderLeft: `3px solid ${active === i ? "#d8b78c" : "transparent"}`, background: active === i ? "rgba(216,183,140,.05)" : "transparent", borderBottom: "1px solid rgba(0,0,0,.05)", transition: "all .2s", display: "flex", gap: 12, alignItems: "flex-start" }}>
                <div style={{ flexShrink: 0, paddingTop: 2 }}>
                  <div style={{ fontFamily: "'Cormorant Garamond', Georgia, serif", fontSize: 20, color: active === i ? "#d8b78c" : "#010000", fontWeight: 600, lineHeight: 1, whiteSpace: "nowrap" }}>{s.time}</div>
                  <div style={{ fontFamily: "'Lato', sans-serif", fontSize: 9, color:"#010000", marginTop: 3 }}>{s.dur}</div>
                </div>
                <div>
                  <div style={{ fontFamily: "'Cormorant Garamond', Georgia, serif", fontSize: 15, fontWeight: 600, color:"#010000", lineHeight: 1.3 }}>{s.block}</div>
                  {s.instructor && <div style={{ fontFamily: "'Lato', sans-serif", fontSize: 9, color: active === i ? "#d8b78c" : "#FBF7EE", marginTop: 2, letterSpacing: "0.06em" }}>{s.instructor}</div>}
                </div>
              </div>
            ))}
          </div>
          <div style={{ background: "#010000" }}>
            {active !== null && (schedule || [])[active] ? (
              <div key={active} style={{ minHeight: 320 }}>
                <ScheduleDetail block={(schedule || [])[active]} />
              </div>
            ) : (
              <div style={{ padding: "36px 40px", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", minHeight: 320, gap: 12 }}>
                <span style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 36, color:"#d8b78c" }}>✦</span>
                <p style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 15, color:"#d8b78c", fontStyle: "italic", textAlign: "center" }}>Select a time block<br />to see what happens in that session</p>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}


