              <p style={{ fontFamily: "'Lato', sans-serif", color: "#A48D6E", fontSize: 10, marginTop: 16, letterSpacing: "0.18em", fontWeight: 700, textTransform: "uppercase" }}>admissions@excaliburacademy.org</p>
