                  <span key={tag} style={{ fontFamily: eyebrow_font, fontSize: 8, letterSpacing: "0.12em", color:"#FBF7EE", border: "1px solid rgba(0,0,0,.3)", padding: "4px 10px", textTransform: "uppercase" }}>{tag}</span>
