                                    {m.slug && <button onClick={e=>{e.stopPropagation();setPage(`module:${m.slug}`)}} style={{ marginTop:20, fontFamily:eyebrow_font, fontSize:8, letterSpacing:"0.2em", padding:"10px 24px", background:"transparent", border:"1px solid rgba(0,0,0,.2)", color:"#010000", textTransform:"uppercase", cursor:"pointer", fontWeight:600 }}>Full Module Description →</button>}
