  const fMods = [
    { n:"01", title:"Public Speaking & Leadership Communication", tagline:"Presence. Persuasion. Command.", sub:"Senior Public Speaking Instructor · Every session · All 14 weeks (Foundation) · All 16 weeks (Venture)",
      body:"Every serious path in leadership begins with the ability to stand before others and speak with force, clarity, and composure. Students work from fundamentals through to Aristotelian rhetoric, narrative architecture, and the ability to hold attention without spectacle. Sixty-plus individual reps by semester end.",
      learn:["Voice mechanics — projection, pacing, tone variation, and the power of silence","Physical presence — posture, eye contact, and gesture that conveys authority","Aristotle\'s three modes: ethos, pathos, logos","Narrative architecture — tension, clarity, one unforgettable idea","Impromptu speaking, advanced rhetoric, debate and Q&A defence","Executive communication — briefing a team, presenting to adults"] },
    { n:"02", title:"Financial Literacy & Business Acumen", tagline:"Understand money. Think like an owner.",
      body:"Reading a P&L, unit economics, pricing strategy, equity structures, and how investors actually evaluate a business. Not finance for general audiences — finance the way people who run things understand it.",
      learn:["Revenue vs. profit — why the difference matters","How to read a P&L, balance sheet, and cash flow statement","Unit economics — CAC, LTV, contribution margin","Pricing strategy — cost-plus, value-based, competitive, dynamic","Equity structures and investor evaluation — multiples, EBITDA","Live financial analysis of real local businesses"] },
    { n:"03", title:"Business Model Analysis", tagline:"Break down any business. Find the logic.", sub:"Cases: Netflix · Apple · Amazon · Airbnb · Tesla",
      body:"The eight archetypes. Competitive advantage. Disruption. Vulnerability. Every student leaves able to explain any company\'s model, margin structure, and single greatest strategic risk within five minutes.",
      learn:["The eight business models — subscription, marketplace, DTC, advertising, franchise, freemium, professional services, hardware-plus-consumable","Competitive advantage — cost leadership, differentiation, focus, network effects","Vulnerability mapping — the greatest strategic risk in any business","Investor Briefing format — how analysts present to investment committees"] },
    { n:"04", title:"The Art of Selling & Marketing", tagline:"Persuasion with integrity. Influence with purpose.", sub:"Academy Dean + Outside Sales Specialist",
      body:"Consultative selling, Cialdini\'s principles of influence, objection handling, brand strategy, and the full marketing stack from customer psychology to digital channels. Closes with a live sales role-play.",
      learn:["The psychology of persuasion — why people buy, what triggers decisions","Consultative selling — understanding a customer\'s real need","Objection handling — welcoming resistance and responding without defensiveness","Brand identity — name, positioning, voice, visual presence","The marketing funnel — awareness, consideration, conversion, retention","Live sales role-play with structured faculty feedback"] },
    { n:"05", title:"Capital Markets, Investing & Wealth Management", tagline:"Capital. Risk. Markets. Wealth.", sub:"Academy Dean — Former Citigroup MD",
      body:"How stock markets work, how institutional investors think, how venture capital fits into the capital stack. Crypto, bonds, ETFs, private equity, and a live two-week mock portfolio simulation.",
      learn:["Stock markets — price discovery, market makers, trading mechanics","Stocks, bonds, ETFs, mutual funds — what each is and why each exists","Crypto and digital assets — blockchain basics and valuation","Venture capital and private equity — how they work and return capital","Trading simulation — students manage a mock portfolio for 2 weeks"] },
    { n:"06", title:"Leadership, Influence & Decision-Making", tagline:"Lead with earned authority, not borrowed title.", sub:"Academy Dean — Signature: CEO Crisis Simulation",
      body:"The five forms of power, emotional intelligence, conflict resolution, and decision-making under genuine uncertainty. Culminates in a full-group CEO Crisis Simulation — a live, unscripted emergency.",
      learn:["The five forms of power — legitimate, reward, coercive, expert, referent","Emotional intelligence — self-awareness, self-regulation, empathy","Decision-making under uncertainty — frameworks for consequential choices","Conflict resolution — navigating disagreement while maintaining relationships","CEO Crisis Simulation — running a fictional company through a real-time emergency"] },
    { n:"07", title:"Negotiation & Human Psychology", tagline:"Understand people. Command outcomes.", sub:"Live simulations: salary · deal terms · equity · partnership",
      body:"The psychology of decision-making, cognitive biases, interest-based negotiation, Cialdini\'s influence architecture, and the ethics of persuasion. Multiple live simulations with direct faculty feedback.",
      learn:["Cognitive biases — anchoring, loss aversion, reciprocity","Interest-based negotiation — separating positions from underlying needs","BATNA, ZOPA, anchor-setting, and concession strategy","Active listening and reading non-verbal signals","Cialdini\'s six drivers of human behavior"] },
    { n:"08", title:"Legal Foundations for Founders", tagline:"Know what you\'re signing before you sign it.", sub:"Outside Specialist — Practicing Attorney with Startup Experience",
      body:"Most founders do not make legal mistakes because they are careless. They make them because they do not yet know what can go wrong: the wrong entity, unclear ownership, missing IP protection, weak founder agreements, careless contracts, or terms they did not fully understand until it was too late.\n\nThis module gives students the legal literacy every young founder needs before building a venture. It is a practical introduction to the structures, documents, and decisions that shape the first years of a company.\n\nStudents learn how companies are formed, how ownership is divided, how intellectual property is protected, how contracts create obligations, and why the details of founder agreements, NDAs, equity terms, and term sheets matter before a serious business relationship begins.",
      learn:["Business entity types: LLC, C-corp, S-corp, sole proprietorship, and when each structure makes sense","Equity structure: ownership splits, dilution, vesting schedules, cliff periods, and what happens when a co-founder leaves","Founder agreements: roles, responsibilities, equity, decision rights, vesting, IP assignment, and dispute prevention","Intellectual property: trademarks, copyrights, patents, trade secrets, ownership, and protection of what students build","Contracts and NDAs: what makes an agreement binding, what clauses create risk, and what should never be signed casually","Employment and contractor basics: IP assignment, confidentiality, compensation, and early-team agreements","Term sheet basics: valuation, equity, liquidation preference, control rights, investor protections, and the clauses founders must understand","Cap tables: how ownership changes over time and why early mistakes become expensive later","How to work with a lawyer: what to ask, what to understand yourself, and when professional legal guidance is necessary"] },
    { n:"09", title:"Personal Finance & Wealth Building", tagline:"Earning money is only the beginning.", sub:"Academy Dean + Outside Specialist (Financial Planner or Wealth Advisor)",
      body:"Most students are told to work hard, get into a good university, and eventually earn a strong income. Very few are taught what to do with money once they have it — whether that income comes from a summer job, part-time work, freelance projects, a first salary, or profit from a business they build.\n\nThis module introduces students to the principles of personal finance and long-term wealth building. They learn how financially disciplined people think about income, spending, saving, taxes, credit, debt, investing, real estate, compounding, risk, liquidity, and family capital. The goal is not to turn students into financial advisors. It is to give them the literacy and judgment to manage money responsibly, ask better questions, avoid common mistakes, and start thinking about wealth with maturity.\n\nStudents examine the difference between earning income and building wealth — and why early decisions, even small ones, can create a structural advantage over time.",
      learn:["Income management: how to handle money responsibly, whether it comes from a summer job, part-time work, freelance income, business profit, or a future full-time salary","Budgeting and cash management: building a personal budget, tracking spending, and understanding where money actually goes","Credit building: credit scores, credit cards, utilization, payment history, responsible borrowing, and how early mistakes can affect future options","Tax fundamentals: how income tax works, why tax planning matters, and how employees, contractors, founders, and business owners are taxed differently","Compound interest: how money grows over time, applied to a teenager's timeline with real numbers","Roth IRA vs. traditional IRA vs. 401(k): what each account is, how they differ, and why starting early matters","Debt: good debt vs. bad debt, interest rates, credit cards, student loans, and how borrowing can help or damage wealth creation","Real estate as a wealth vehicle: appreciation, leverage, rental income, cash flow, and why many wealthy families own property","Insurance and protection: why wealth must be protected, not only grown","Emergency funds and liquidity: how much cash to keep, where to keep it, and why access matters","Family capital and wealth structures: how financially accomplished families think about trusts, estate planning, diversification, asset protection, and generational wealth","Common mistakes young earners make in their first years of income — and how to avoid them"] },
    { n:"10", title:"Public Relations & Crisis Communication", tagline:"Reputation is built quietly. It can be lost overnight.", sub:"Outside Specialist — PR Professional or Communications Executive",
      body:"A brand is not only what it sells. It is what people believe about it. In a world of screenshots, viral posts, public criticism, founder scandals, failed apologies, and instant judgment, reputation has become one of the most valuable assets a company or leader can have.\n\nThis module teaches students how public narrative is built, protected, and repaired. They learn the difference between earned, paid, and owned media; how journalists think; how a story becomes news; how social media can turn one mistake into a crisis; and why the first response often determines whether a situation is contained or made worse.\n\nStudents study famous corporate and founder reputation crises, then practice building statements, answering difficult questions, and communicating clearly when the room — or the public — is watching. The goal is not spin. The goal is judgment: knowing what to say, what not to say, when to speak, who should speak, and how to protect trust when it matters most.",
      learn:["Earned, paid, and owned media: how each serves a different purpose in building reputation","How journalists think: what makes a story, what gets ignored, and what turns into a headline","Founder and executive reputation: how personal conduct, interviews, social media, and public image affect trust","Crisis communication frameworks: what to say, when to say it, who speaks, and what must be avoided","The first 24 hours: why the initial response often determines whether a crisis is contained or amplified","Social media escalation: how screenshots, comments, bad apologies, and viral moments can reshape public perception","Statement writing: how to draft a clear, responsible, credible response without making the situation worse","Media interviews: how to answer difficult questions without losing composure or saying more than intended","Case studies: Tylenol 1982, Airbnb COVID-19, United Airlines 2017, WeWork, celebrity-founder crises, and modern social media backlash"] },
    { n:"11", title:"Industry Sectors Rotation", tagline:"Know every industry. Own any room.", sub:"Monthly Rotating Guest Practitioners · 4 sectors in Foundation Semester",
      body:"Each month, students are introduced to a different industry through a working practitioner who knows it from the inside. The goal is not surface-level career exposure. It is to help students understand how industries actually operate: how money moves, where opportunity forms, what skills matter, what risks define the field, and what kind of people succeed in each room.\n\nDuring the Foundation Semester, students explore five major sectors — Technology & Startups, Finance & Investment, Real Estate, Sports & Auto Racing, and Media & Entertainment — while maintaining a running Sector Journal. In each entry, students document what they learned, how the industry works, what surprised them, what careers or ventures it may open, and what questions they would ask if they were sitting across from a founder, investor, executive, operator, athlete, creator, or industry leader in that field.",
      learn:[] },

  ];

